function formatDateDDMMYYYY(dateStr) {
  if (!dateStr) return '';
  const dt = new Date(dateStr);
  if (Number.isNaN(dt.getTime())) return dateStr;
  const dd = String(dt.getDate()).padStart(2, '0');
  const mm = String(dt.getMonth() + 1).padStart(2, '0');
  const yyyy = dt.getFullYear();
  return `${dd}-${mm}-${yyyy}`;
}

// Split text into chunks of ~4000 chars, breaking at paragraph boundaries
function chunkText(text, maxLen = 4000, overlap = 200) {
  if (!text || text.length <= maxLen) return [text || ''];
  const paragraphs = text.split(/\n\n+/);
  const chunks = [];
  let current = '';
  for (const para of paragraphs) {
    if (current.length + para.length + 2 > maxLen && current.length > 0) {
      chunks.push(current.trim());
      // Keep last `overlap` chars for context continuity
      current = current.slice(-overlap) + '\n\n' + para;
    } else {
      current += (current ? '\n\n' : '') + para;
    }
  }
  if (current.trim()) chunks.push(current.trim());
  return chunks;
}

const results = [];
for (const item of items) {
  const d = item.json;
  if (!d.extracted_text) continue;

  const decisionDate = formatDateDDMMYYYY(d.decision_date);
  const chunks = chunkText(d.extracted_text);

  for (let i = 0; i < chunks.length; i++) {
    const header =
      'Document: ' + (d.title || '') + '\n' +
      'File: ' + (d.file_name || '') + '\n' +
      'Source: ' + (d.decision_body_code || '') + ' ' + (d.decision_body_name || '') +
      (decisionDate ? ' от ' + decisionDate : '') + '\n' +
      (chunks.length > 1 ? 'Chunk: ' + (i + 1) + '/' + chunks.length + '\n' : '') +
      '\n';

    const content = header + chunks[i];

    const metadata = {
      document_id: d.document_id,
      title: d.title,
      file_name: d.file_name,
      decision_body: d.decision_body_code || null,
      decision_date: decisionDate || null,
      chunk_index: i,
      total_chunks: chunks.length,
    };

    results.push({
      json: {
        document_id: d.document_id,
        chunk_index: i,
        content,
        metadata,
      },
    });
  }
}
return results;

return items.map(item => {
  const d = item.json;
  const embedding = d.data[0].embedding;
  const loopItem = $('Loop Over Chunks').first().json;
  return {
    json: {
      document_id: loopItem.document_id,
      chunk_index: loopItem.chunk_index,
      content: loopItem.content,
      metadata: loopItem.metadata,
      embedding,
    },
  };
});
